59	// SubscriptionTransport is the minimal GraphQL-over-WebSocket transport used
60	// by the Axon client subscription path.
61	type SubscriptionTransport interface {
62		Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error)
63	}
