72	// Query forwards GraphQL queries and mutations to the query transport.
73	func (d DualTransport) Query(ctx context.Context, query string, variables map[string]any, response any) error {
74		if d.Queries == nil {
75			return fmt.Errorf("axon: query transport not configured")
76		}
77		return d.Queries.Query(ctx, query, variables, response)
78	}
