80	// Subscribe forwards GraphQL subscriptions to the subscription transport.
81	func (d DualTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
82		if d.Subscriptions == nil {
83			return nil, fmt.Errorf("axon: subscription transport not configured")
84		}
85		return d.Subscriptions.Subscribe(ctx, query, variables)
