15	// BackendAxon selects the axon-backed RawBackend. Per TD-030 D3 the Axon
16	// shape splits beads from their events: one row per bead in the
17	// ddx_beads collection, plus one entity per event in the
18	// ddx_bead_events collection linked back to its bead via event_of.
19	//
20	// When a GraphQL transport is configured (test code wires one in via the
21	// AxonBackend.GraphQLTransport field), AxonBackend speaks that wire shape
22	// directly. The fallback path keeps the existing in-process JSONL emulation
23	// for callers that have not wired a transport yet.
24	//
25	// NewStore routes to AxonBackend when bead.backend is set to axon in the
26	// config or via DDX_BEAD_BACKEND.
27	const BackendAxon = "axon"
28	
29	// axonSchemaVersion is written into every persisted entity. Schema upgrades
30	// are handled lazy-on-read until axon FEAT-017 ships native schema
31	// migration (per TD-030 v1 policy on schema versioning).
32	const axonSchemaVersion = 1
33	
34	// AxonDirName is the per-store axon subdirectory under .ddx that holds the
35	// two-collection snapshot files and the lock dir.
36	const AxonDirName = "axon"
37	
38	// AxonBeadsCollection / AxonEventsCollection are the logical collection names
39	// from TD-030's schema mapping. They are surfaced as the on-disk filenames so
40	// inspecting the directory tells the operator which collection an entity
41	// belongs to.
42	const (
43		AxonBeadsCollection  = "ddx_beads"
44		AxonEventsCollection = "ddx_bead_events"
45	)
46	
47	// AxonBackend stores the bead corpus in axon's two-collection shape.
48	//
49	// On WriteAll the backend splits each bead's inline Extra["events"] into one
50	// entity per event under ddx_bead_events and persists the bead row (sans
51	// inline events) under ddx_beads. ReadAll re-merges events back into
52	// Extra["events"] so the higher-level Store and the chaos suite see the
53	// uniform inline-events shape they expect.
54	//
55	// Beads with Extra[events_attachment] set (post-Close externalisation) are
56	// persisted with their events array empty in axon's events collection. The
57	// attachment file remains the canonical source for those events so Store's
58	// existing read path (eventsForBead) keeps working unchanged.
59	type AxonBackend struct {
60		Dir              string
61		BeadsFile        string
62		EventsFile       string
63		LockDir          string
64		LockWait         time.Duration
65		GraphQLTransport AxonGraphQLTransport
66		GraphQLClient    any
67	}
68	
69	// AxonGraphQLTransport is the injectable GraphQL execution boundary used by
70	// the Axon backend. It mirrors the generated client's transport surface, so a
71	// caller can wire a real transport into the future GraphQL implementation
72	// without changing the storage code that uses this backend.
73	type AxonGraphQLTransport interface {
74		Query(ctx context.Context, query string, variables map[string]any, response any) error
75	}
76	
77	// Compile-time check: AxonBackend satisfies RawBackend.
78	var _ RawBackend = (*AxonBackend)(nil)
79	
80	// NewAxonBackend constructs an axon-backed RawBackend rooted at dir. dir is
81	// the .ddx directory for the project; collection files and the lock live
82	// under <dir>/axon/.
83	func NewAxonBackend(dir string, lockWait time.Duration) *AxonBackend {
84		root := filepath.Join(dir, AxonDirName)
85		return &AxonBackend{
86			Dir:        root,
87			BeadsFile:  filepath.Join(root, AxonBeadsCollection+".jsonl"),
88			EventsFile: filepath.Join(root, AxonEventsCollection+".jsonl"),
89			LockDir:    filepath.Join(root, ".lock"),
90			LockWait:   lockWait,
91		}
92	}
93	
94	func (a *AxonBackend) Init() error {
95		if err := os.MkdirAll(a.Dir, 0o755); err != nil {
96			return fmt.Errorf("bead: axon init dir: %w", err)
97		}
98		for _, path := range []string{a.BeadsFile, a.EventsFile} {
99			f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY, 0o644)
100			if err != nil {
101				return fmt.Errorf("bead: axon init %s: %w", path, err)
102			}
103			if err := f.Close(); err != nil {
104				return fmt.Errorf("bead: axon close %s: %w", path, err)
105			}
106		}
107		return nil
108	}
