110	const (
111		axonReadCorpusQuery     = `query AxonReadCorpus { ddxBeads { _collection schema_version data } ddxBeadEvents { _collection schema_version event_of index event } }`
112		axonWriteCorpusMutation = `mutation AxonWriteCorpus($beads: [AxonBeadRowInput!]!, $events: [AxonEventRowInput!]!) { saveCorpus(beads: $beads, events: $events) { ok } }`
113	)
114	
115	type axonCorpusResponse struct {
116		Beads  []axonEntityEnvelope `json:"ddxBeads"`
117		Events []axonEventEnvelope  `json:"ddxBeadEvents"`
118	}
119	
120	type axonWriteCorpusResponse struct {
121		SaveCorpus axonWriteCorpusResult `json:"saveCorpus"`
122	}
123	
124	type axonWriteCorpusResult struct {
125		OK bool `json:"ok"`
126	}
