128	// ReadAll loads bead rows and event entities from disk and re-merges events
129	// back into each bead's Extra["events"]. Orphan events (event_of pointing at
130	// a missing bead, e.g. after a partial-write crash) are silently dropped.
131	func (a *AxonBackend) ReadAll() ([]Bead, error) {
132		if transport := a.graphQLTransport(); transport != nil {
133			var resp axonCorpusResponse
134			if err := transport.Query(context.Background(), axonReadCorpusQuery, nil, &resp); err != nil {
135				return nil, fmt.Errorf("bead: axon read corpus: %w", err)
136			}
137			beads := make([]Bead, 0, len(resp.Beads))
138			for _, env := range resp.Beads {
139				if env.Collection != AxonBeadsCollection || env.Data.ID == "" {
140					continue
141				}
142				beads = append(beads, env.Data.Bead)
143			}
144			events := make([]axonEventRecord, 0, len(resp.Events))
145			for _, env := range resp.Events {
146				if env.Collection != AxonEventsCollection || env.EventOf == "" {
147					continue
148				}
149				events = append(events, axonEventRecord{
150					beadID: env.EventOf,
151					index:  env.Index,
152					event:  env.Event,
153				})
154			}
155			sort.SliceStable(events, func(i, j int) bool {
156				if events[i].beadID != events[j].beadID {
157					return events[i].beadID < events[j].beadID
158				}
159				return events[i].index < events[j].index
160			})
161			byID := make(map[string]*Bead, len(beads))
162			for i := range beads {
163				byID[beads[i].ID] = &beads[i]
164			}
165			counts := make(map[string]int, len(events))
166			for _, ev := range events {
167				if _, ok := byID[ev.beadID]; !ok {
168					continue
169				}
170				counts[ev.beadID]++
171			}
172			grouped := make(map[string][]BeadEvent, len(counts))
173			for id, count := range counts {
174				grouped[id] = make([]BeadEvent, 0, count)
175			}
176			for _, ev := range events {
177				if _, ok := byID[ev.beadID]; !ok {
178					continue
179				}
180				grouped[ev.beadID] = append(grouped[ev.beadID], ev.event)
181			}
182			for id, evs := range grouped {
183				b := byID[id]
184				// Always copy b.Extra before writing; two concurrent ReadAll calls
185				// may share the underlying map (shallow-copy race via Bead copy-by-value).
186				fresh := make(map[string]any, len(b.Extra)+1)
187				for k, v := range b.Extra {
188					fresh[k] = v
189				}
190				fresh["events"] = encodeEventsForExtra(evs)
191				b.Extra = fresh
192			}
193			return beads, nil
194		}
195	
196		beads, err := a.readBeadRows()
197		if err != nil {
198			return nil, err
199		}
200		events, err := a.readEventEntities()
201		if err != nil {
202			return nil, err
203		}
204		// Index beads by id so we can attach events and drop orphans.
205		byID := make(map[string]*Bead, len(beads))
206		for i := range beads {
207			byID[beads[i].ID] = &beads[i]
208		}
209		// Group events by bead id with exact per-bead capacity so the read path
210		// does not repeatedly grow slices while rebuilding the inline shape.
211		counts := make(map[string]int, len(events))
212		for _, ev := range events {
213			if _, ok := byID[ev.beadID]; !ok {
214				continue // orphan
215			}
216			counts[ev.beadID]++
217		}
218		grouped := make(map[string][]BeadEvent, len(counts))
219		for id, count := range counts {
220			grouped[id] = make([]BeadEvent, 0, count)
221		}
222		for _, ev := range events {
223			if _, ok := byID[ev.beadID]; !ok {
224				continue
225			}
226			grouped[ev.beadID] = append(grouped[ev.beadID], ev.event)
227		}
228		for id, evs := range grouped {
229			b := byID[id]
230			// Skip beads whose events have been externalised — the attachment file
231			// is the canonical source post-close and inlining stale events would
232			// duplicate the history.
233			if hasEventsAttachment(b) {
234				continue
235			}
236			// Always copy b.Extra before writing; two concurrent ReadAll calls
237			// may share the underlying map (shallow-copy race via Bead copy-by-value).
238			fresh := make(map[string]any, len(b.Extra)+1)
239			for k, v := range b.Extra {
240				fresh[k] = v
241			}
242			fresh["events"] = encodeEventsForExtra(evs)
243			b.Extra = fresh
244		}
245		return beads, nil
246	}
