248	// WriteAll splits inline events from each bead and persists both collections.
249	// Writes are serialised at the directory-lock layer (WithLock); this method
250	// rewrites both files in temp+rename style so a crash mid-write leaves the
251	// previous snapshot intact rather than producing torn rows.
252	func (a *AxonBackend) WriteAll(beads []Bead) error {
253		if transport := a.graphQLTransport(); transport != nil {
254			sort.Slice(beads, func(i, j int) bool { return beads[i].ID < beads[j].ID })
255			var rowBeads []axonEntityEnvelope
256			var rowEvents []axonEventEnvelope
257			for _, b := range beads {
258				var events []BeadEvent
259				if b.Extra != nil {
260					if raw, ok := b.Extra["events"]; ok {
261						events = decodeBeadEvents(raw)
262					}
263				}
264				stripped := beadWithoutInlineEvents(b)
265				if stripped.Extra != nil {
266					delete(stripped.Extra, EventsAttachmentExtraKey)
267				}
268				row, err := axonEncodeBead(stripped)
269				if err != nil {
270					return fmt.Errorf("bead: axon marshal %s: %w", b.ID, err)
271				}
272				var env axonEntityEnvelope
273				if err := json.Unmarshal(row, &env); err != nil {
274					return fmt.Errorf("bead: axon envelope %s: %w", b.ID, err)
275				}
276				rowBeads = append(rowBeads, env)
277				for i, ev := range events {
278					data, err := axonEncodeEvent(b.ID, i, ev)
279					if err != nil {
280						return fmt.Errorf("bead: axon marshal event %s/%d: %w", b.ID, i, err)
281					}
282					var eventEnv axonEventEnvelope
283					if err := json.Unmarshal(data, &eventEnv); err != nil {
284						return fmt.Errorf("bead: axon envelope event %s/%d: %w", b.ID, i, err)
285					}
286					rowEvents = append(rowEvents, eventEnv)
287				}
288			}
289			var resp axonWriteCorpusResponse
290			vars := map[string]any{
291				"beads":  rowBeads,
292				"events": rowEvents,
293			}
294			if err := transport.Query(context.Background(), axonWriteCorpusMutation, vars, &resp); err != nil {
295				return fmt.Errorf("bead: axon write corpus: %w", err)
296			}
297			return nil
298		}
299	
300		if err := os.MkdirAll(a.Dir, 0o755); err != nil {
301			return fmt.Errorf("bead: axon mkdir: %w", err)
302		}
303		sort.Slice(beads, func(i, j int) bool { return beads[i].ID < beads[j].ID })
304	
305		var beadsBuf, eventsBuf bytes.Buffer
306		for _, b := range beads {
307			// Extract and strip inline events for the split.
308			var events []BeadEvent
309			if b.Extra != nil {
310				if raw, ok := b.Extra["events"]; ok {
311					events = decodeBeadEvents(raw)
312				}
313			}
314			stripped := beadWithoutInlineEvents(b)
315			row, err := axonEncodeBead(stripped)
316			if err != nil {
317				return fmt.Errorf("bead: axon marshal %s: %w", b.ID, err)
318			}
319			beadsBuf.Write(row)
320			beadsBuf.WriteByte('\n')
321	
322			for i, ev := range events {
323				data, err := axonEncodeEvent(b.ID, i, ev)
324				if err != nil {
325					return fmt.Errorf("bead: axon marshal event %s/%d: %w", b.ID, i, err)
326				}
327				eventsBuf.Write(data)
328				eventsBuf.WriteByte('\n')
329			}
330		}
331	
332		// Write events first so a crash between the two writes leaves orphan
333		// events (which ReadAll silently drops) rather than a bead row whose
334		// events have not landed yet — favouring the safer side of the partial-
335		// write window for an audit log.
336		if err := writeAtomicFile(a.EventsFile, eventsBuf.Bytes()); err != nil {
337			return fmt.Errorf("bead: axon write events: %w", err)
338		}
339		if err := writeAtomicFile(a.BeadsFile, beadsBuf.Bytes()); err != nil {
340			return fmt.Errorf("bead: axon write beads: %w", err)
341		}
342		return nil
343	}
