473	func (a *AxonBackend) readBeadRows() ([]Bead, error) {
474		data, err := os.ReadFile(a.BeadsFile)
475		if os.IsNotExist(err) {
476			return nil, nil
477		}
478		if err != nil {
479			return nil, fmt.Errorf("bead: axon read %s: %w", a.BeadsFile, err)
480		}
481		scanner := bufio.NewScanner(bytes.NewReader(data))
482		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
483		out := make([]Bead, 0, bytes.Count(data, []byte{'\n'}))
484		for scanner.Scan() {
485			line := bytes.TrimSpace(scanner.Bytes())
486			if len(line) == 0 {
487				continue
488			}
489			var env axonEntityEnvelope
490			if err := json.Unmarshal(line, &env); err != nil {
491				return nil, fmt.Errorf("bead: axon parse bead row: %w", err)
492			}
493			if env.Collection != AxonBeadsCollection || env.Data.ID == "" {
494				continue
495			}
496			out = append(out, env.Data.Bead)
497		}
498		if err := scanner.Err(); err != nil {
499			return nil, fmt.Errorf("bead: axon scan beads: %w", err)
500		}
501		return foldLatestBeads(out), nil
502	}
